public Query build()
{
    Query qry = next build();

    if(buildReceiptQtyQuery)
    {
        QueryBuildDataSource qbds = qry.dataSourceTable(tableNum(InventAgingReceiptView));
        qbds.addSelectionField(fieldNum(InventAgingReceiptView, PwcTransDate), SelectionField::Min);
    }
    return qry;
}
